import React from "react";
import { NavLink, useNavigate } from "react-router-dom";

const Sidebar = ({ role }) => {
  const navigate = useNavigate();
  const logout = () => { localStorage.clear(); navigate("/login"); };

  const freelancerMenu = [
    { to: "/freelancer/dashboard",     icon: "📊", label: "Dashboard" },
    { to: "/freelancer/find-projects", icon: "🔎", label: "Find Projects" },
    { to: "/freelancer/my-projects",   icon: "📁", label: "My Projects" },
    { to: "/freelancer/proposals",     icon: "📄", label: "My Proposals" },
    { to: "/freelancer/earnings",      icon: "💰", label: "Earnings" },
    { to: "/freelancer/portfolio",     icon: "🗂️", label: "Portfolio" },
    { to: "/freelancer/messages",      icon: "💬", label: "Messages" },
    { to: "/freelancer/profile",       icon: "👤", label: "Profile" },
  ];

  const clientMenu = [
    { to: "/client/dashboard",         icon: "📊", label: "Dashboard" },
    { to: "/client/post-project",      icon: "➕", label: "Post Project" },
    { to: "/client/my-projects",       icon: "📁", label: "My Projects" },
    { to: "/client/freelancers",       icon: "👥", label: "Freelancers" },
    { to: "/client/rate-freelancer",   icon: "⭐", label: "Rate Freelancer" },
    { to: "/client/messages",          icon: "💬", label: "Messages" },
    { to: "/client/settings",          icon: "⚙️", label: "Settings" },
  ];

  const adminMenu = [
    { to: "/admin/dashboard",  icon: "📊", label: "Dashboard" },
    { to: "/admin/users",      icon: "👥", label: "Manage Users" },
    { to: "/admin/projects",   icon: "📁", label: "Manage Projects" },
    { to: "/admin/reports",    icon: "📈", label: "Reports" },
    { to: "/admin/settings",   icon: "⚙️", label: "Settings" },
  ];

  const menu = role === "admin" ? adminMenu : role === "client" ? clientMenu : freelancerMenu;
  const user = JSON.parse(localStorage.getItem("user") || "{}");

  return (
    <div className="w-64 bg-gray-900 text-white h-screen flex flex-col fixed left-0 top-0">
      {/* LOGO */}
      <div className="p-5 border-b border-gray-700">
        <div className="flex items-center gap-3">
          <div className="w-9 h-9 bg-teal-500 rounded-lg flex items-center justify-center text-lg">💼</div>
          <span className="font-bold text-lg">FreelanceHub</span>
        </div>
      </div>

      {/* USER INFO */}
      <div className="p-4 border-b border-gray-700">
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-teal-600 rounded-full flex items-center justify-center font-bold text-sm">
            {user.name?.charAt(0).toUpperCase()}
          </div>
          <div>
            <p className="font-semibold text-sm">{user.name}</p>
            <p className="text-gray-400 text-xs capitalize">{user.role}</p>
          </div>
        </div>
      </div>

      {/* MENU */}
      <nav className="flex-1 p-3 overflow-y-auto">
        <p className="text-gray-500 text-xs font-medium px-3 mb-2 mt-2">MENU</p>
        {menu.map((item) => (
          <NavLink
            key={item.to}
            to={item.to}
            className={({ isActive }) =>
              `flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm mb-1 transition ${
                isActive ? "bg-teal-600 text-white font-medium" : "text-gray-300 hover:bg-gray-800"
              }`
            }
          >
            <span>{item.icon}</span>
            <span>{item.label}</span>
          </NavLink>
        ))}
      </nav>

      {/* LOGOUT */}
      <div className="p-4 border-t border-gray-700">
        <button
          onClick={logout}
          className="w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm text-gray-300 hover:bg-red-900 hover:text-white transition"
        >
          🚪 Logout
        </button>
      </div>
    </div>
  );
};

export default Sidebar;
